external_knowledge:
- 'Star in the constellation of active reviewers' refers to users with an active status; 
- 'Glowing review' is a metaphor for a rating greater than 4;
- 'Sorted from the most radiant to the least' means ordered by rating in descending order.

sql:
SELECT books.title, genres.genre_name
FROM books
INNER JOIN genres ON books.genre_id = genres.genre_id;
